final:
module top_module(
    input ZZ_x,
    input y,
    output n
);
    assign n = ~(ZZ_x | y);
endmodule

module N(
    input ZZ_x,
    input y,
    output n
);
    assign n = ~(ZZ_x | y);
endmodule

module top_module(
    input ZZ_x,
    input y,
    output n
);
    wire m1_out, m2_out, n1_out, n2_out;
    wire nor_out, xor_out;

    M m1(.ZZ_x(ZZ_x), .y(y), .n(m1_out));
    M m2(.ZZ_x(ZZ_x), .y(y), .n(m2_out));
    N n1(.ZZ_x(ZZ_x), .y(y), .n(n1_out));
    N n2(.ZZ_x(ZZ_x), .y(y), .n(n2_out));

    assign nor_out = ~(m1_out | n1_out);
    assign xor_out = m2_out ^ n2_out;

    assign n = nor_out & xor_out;
endmodule
